+        }
+    }
+
+    // Handle PyString
+    if (T == PyString) {
+        return value.len() > 0;
+    }
+
+    // Handle PyInt
+    if (T == PyInt) {
+        return value.value != 0;
+    }
+
+    // Handle PyBool
+    if (T == PyBool) {
